-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil, err
    end

    if REDIS_PASSWORD then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            ngx.log(ngx.ERR, "Failed to authenticate with Redis: ", err)
            return nil, err
        end
    end

    return red
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Validate plugin code for basic safety checks
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" or #code == 0 then
        return false, "Plugin code is empty or not a string"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size of 64KB"
    end

    -- Block dangerous patterns
    local dangerous_patterns = {
        { pattern = "os%s*%.%s*execute", desc = "os.execute" },
        { pattern = "os%s*%.%s*remove", desc = "os.remove" },
        { pattern = "os%s*%.%s*rename", desc = "os.rename" },
        { pattern = "os%s*%.%s*tmpname", desc = "os.tmpname" },
        { pattern = "io%s*%.", desc = "io library" },
        { pattern = "dofile", desc = "dofile" },
        { pattern = "loadfile", desc = "loadfile" },
        { pattern = "require%s*%(?%s*['\"]ffi", desc = "FFI library" },
        { pattern = "require%s*%(?%s*['\"]os", desc = "os library via require" },
        { pattern = "require%s*%(?%s*['\"]io", desc = "io library via require" },
        { pattern = "rawset%s*%(%s*_G", desc = "rawset on _G" },
        { pattern = "rawget%s*%(%s*_G", desc = "rawget on _G" },
        { pattern = "getfenv", desc = "getfenv" },
        { pattern = "setfenv", desc = "setfenv" },
        { pattern = "debug%s*%.", desc = "debug library" },
        { pattern = "package%s*%.", desc = "package library" },
        { pattern = "collectgarbage", desc = "collectgarbage" },
        { pattern = "newproxy", desc = "newproxy" },
        { pattern = "load%s*%(", desc = "nested load()" },
        { pattern = "loadstring%s*%(", desc = "nested loadstring()" },
    }

    for _, check in ipairs(dangerous_patterns) do
        if ngx.re.find(code, check.pattern, "ijo") then
            return false, "Blocked dangerous pattern: " .. check.desc
        end
    end

    return true
end

-- Compile and cache plugin code
local function compile_plugin(plugin_name, code)
    local valid, err = validate_plugin_code(code)
    if not valid then
        return nil, "Validation failed: " .. err
    end

    local load_fn = load or loadstring
    local func, compile_err = load_fn(code, "plugin:" .. plugin_name)
    if not func then
        return nil, "Compilation failed: " .. compile_err
    end

    return func
end

-- Execute a plugin function within a sandbox
local function execute_plugin(plugin_func, request_ctx, plugin_config)
    local sandbox = create_sandbox_env(request_ctx)
    sandbox.plugin_config = plugin_config or {}

    -- Set the sandbox as the function's environment
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(plugin_func, sandbox)
    end

    -- Execute with timeout protection via pcall
    local ok, result = pcall(plugin_func)
    if not ok then
        return nil, "Plugin execution error: " .. tostring(result)
    end

    -- If the plugin returns a function (module pattern), call it
    if type(result) == "function" then
        local ok2, result2 = pcall(result, sandbox.ctx, sandbox.plugin_config)
        if not ok2 then
            return nil, "Plugin handler error: " .. tostring(result2)
        end
        return result2
    end

    -- If the plugin returns a table with handler methods
    if type(result) == "table" then
        return result
    end

    return result
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    -- Check shared dict cache first
    if plugin_cache then
        local cached_code = plugin_cache:get("code:" .. plugin_name)
        if cached_code then
            ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
            return cached_code
        end
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. err
    end

    -- Load plugin code
    local code, err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":code")
    if not code or code == ngx.null then
        release_redis_connection(red)
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Load plugin metadata (optional)
    local meta_json = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    local meta = nil
    if meta_json and meta_json ~= ngx.null then
        local ok, decoded = pcall(cjson.decode, meta_json)
        if ok then
            meta = decoded
        end
    end

    -- Check if plugin is enabled
    if meta and meta.enabled == false then
        release_redis_connection(red)
        return nil, "Plugin '" .. plugin_name .. "' is disabled"
    end

    release_redis_connection(red)

    -- Cache the code in shared dict
    if plugin_cache then
        plugin_cache:set("code:" .. plugin_name, code, PLUGIN_CACHE_TTL)
        if meta_json and meta_json ~= ngx.null then
            plugin_cache:set("meta:" .. plugin_name, meta_json, PLUGIN_CACHE_TTL)
        end
    end

    return code, nil, meta
end

-- Load plugin code from HTTP header
local function load_plugin_from_header()
    local headers = ngx.req.get_headers()

    local plugin_code = headers["X-Gateway-Plugin-Code"]
    if not plugin_code then
        -- Try base64 encoded version
        local encoded = headers["X-Gateway-Plugin-Code-B64"]
        if encoded then
            plugin_code = ngx.decode_base64(encoded)
            if not plugin_code then
                return nil, "Failed to decode base64 plugin code from header"
            end
        end
    end

    if not plugin_code then
        return nil, "No plugin code found in headers"
    end

    local plugin_config_str = headers["X-Gateway-Plugin-Config"]
    local plugin_config = nil
    if plugin_config_str then
        local ok, decoded = pcall(cjson.decode, plugin_config_str)
        if ok then
            plugin_config = decoded
        end
    end

    return plugin_code, nil, plugin_config
end

-- Load plugin configuration from Redis
local function load_plugin_config(plugin_name)
    if plugin_cache then
        local cached = plugin_cache:get("config:" .. plugin_name)
        if cached then
            local ok, decoded = pcall(cjson.decode, cached)
            if ok then return decoded end
        end
    end

    local red, err = get_redis_connection()
    if not red then return {} end

    local config_json = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":config")
    release_redis_connection(red)

    if not config_json or config_json == ngx.null then
        return {}
    end

    if plugin_cache then
        plugin_cache:set("config:" .. plugin_name, config_json, PLUGIN_CACHE_TTL)
    end

    local ok, config = pcall(cjson.decode, config_json)
    if ok then return config end
    return {}
end

-- Get the plugin execution chain for a route
local function get_route_plugins(route_key)
    local red, err = get_redis_connection()
    if not red then return {} end

    local plugins_json = red:get("gateway:route:" .. route_key .. ":plugins")
    release_redis_connection(red)

    if not plugins_json or plugins_json == ngx.null then
        return {}
    end

    local ok, plugins = pcall(cjson.decode, plugins_json)
    if ok and type(plugins) == "table" then
        return plugins
    end
    return {}
end

-- Register a plugin in Redis
local function register_plugin(plugin_name, code, config, meta)
    local valid, err = validate_plugin_code(code)
    if not valid then
        return false, err
    end

    -- Test compilation
    local func, compile_err = compile_plugin(plugin_name, code)
    if not func then
        return false, compile_err
    end

    local red, err = get_redis_connection()
    if not red then
        return false, "Redis connection failed: " .. err
    end

    red:init_pipeline()
    red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":code", code)

    if config then
        red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":config", cjson.encode(config))
    end

    local plugin_meta = meta or {}
    plugin_meta.name = plugin_name
    plugin_meta.registered_at = ngx.now()
    plugin_meta.enabled = true
    red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta", cjson.encode(plugin_meta))

    -- Add to plugin registry
    red:sadd("gateway:plugins:registry", plugin_name)

    local results, err = red:commit_pipeline()
    release_redis_connection(red)

    if not results then
        return false, "Failed to store plugin: " .. err
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
        plugin_cache:delete("config:" .. plugin_name)
        plugin_cache:delete("meta:" .. plugin_name)
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' registered successfully")
    return true
end

-- Invalidate cached plugin
local function invalidate_plugin_cache(plugin_name)
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
        plugin_cache:delete("config:" .. plugin_name)
        plugin_cache:delete("meta:" .. plugin_name)
    end
end

-- List all registered plugins
local function list_plugins()
    local red, err = get_redis_connection()
    if not red then return nil, err end

    local plugin_names, err = red:smembers("gateway:plugins:registry")
    if not plugin_names then
        release_redis_connection(red)
        return nil, err
    end

    local plugins = {}
    for _, name in ipairs(plugin_names) do
        local meta_json = red:get(REDIS_PLUGIN_PREFIX .. name .. ":meta")
        local meta = { name = name }
        if meta_json and meta_json ~= ngx.null then
            local ok, decoded = pcall(cjson.decode, meta_json)
            if ok then meta = decoded end
        end
        table.insert(plugins, meta)
    end

    release_redis_connection(red)
    return plugins
end

-- Delete a plugin from Redis
local function delete_plugin(plugin_name)
    local red, err = get_redis_connection()
    if not red then return false, err end

    red:init_pipeline()
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name .. ":code")
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name .. ":config")